SELECT ?building ?buildingLabel ?height WHERE {
  ?building wdt:P31 wd:Q414165;
          wdt:P2048 ?height;
          wdt:P571 ?completion.
  FILTER(?completion <= "2018-12-31T23:59:59Z"^^xsd:dateTime)
  ?building rdfs:label ?buildingLabel.
  FILTER(LANG(?buildingLabel) = "en")
} ORDER BY DESC(?height) LIMIT 1

